custom_css:
/* Header */
[selector='header'] {
  font-weight: 500;
  font-size: 1.2rem;
  color: #FFF!important;
  background: rgb(113,20,37);
  background: linear-gradient(90deg,rgba(113,20,37,1) 0%,rgba(157,29,54,1) 50%,rgba(113,20,37,1) 100%);
  padding-top: 5px;
  padding-left: 10px;
  padding-right: 10px;
  padding-bottom: 1px;
}
[selector='header'] > p{
  margin-bottom: 0px !important;
}
[selector='title'] {
  font-weight: 700;
  font-size: 1.2rem;
  color: #84171A;
  border-bottom: 2px solid #84171A;
}
[selector='subTitle'] {
  font-weight: 700;
  font-size: 1.2rem;
  color: #63666A;
}
/* Record List Style */
[selector='recordList']>.data-table>.row div {
  padding-right: 0px;
  padding-left: 0px;
}
[selector='recordList'] h4{
  color: #84171A!important;
  border: 0px;
  margin-bottom: 1rem;
  margin-top: 0.75rem;
}
[selector='recordList'] [data-cy="add-row"]::before{
  font-family: "Font Awesome 5 Free";
  content: "+ ";
  padding-right: 8px;
  font-size: 1.2rem;
}
[selector='recordList'] [data-cy="add-row"]{
  background: #84171A;
  color: white !important;
  outline: none !important;
  box-shadow: none;
}
[selector='recordList'] [data-cy="add-row"]:hover{
  background: #000;
}
[selector='recordList'] thead {
  background-color: #84171A;
  color: #FFF;
  text-transform: initial;
  font-size: 90%;
}
[selector='recordList'] tbody {
  border: 1px solid #84171A;
}
[selector='recordList'] tbody tr {
  border-top: 1px solid #84171A;
  padding-left: 1rem;
  padding-right: 1rem;
}
[selector="recordList"] tbody > tr:nth-child(2n+1) {
  background-color: #ededed;
}
[selector='recordList'] tbody  > tr:last-child {
  border-right: 0px;
}
/* Hover Table */
[selector='recordList'] tbody tr:hover{
  background-color: #F3F1EE;
  color: #84171A;
}
/* Loops */
/* Loop with Inputs */
[selector="loop-inputs"] {
    border: 1px solid #84171A;
    padding-top: 1rem;
}
[selector="loop-inputs"] .container-fluid {
    padding-left: 1rem;
    padding-right: 1rem;
}

[selector="loop-inputs"] .container-fluid .row > div:last-child {
  border-right: 0px;
}
/* Hover Loop */
[selector="loop-inputs"] .container-fluid:hover{
  background-color: #F3F1EE;
  color: #84171A;
}
[selector="loop-inputs"] .row.justify-content-md-center > .col-md-auto [title="Add Item"]{
  background-color: #84171A;
  color: #FFF;
  padding-right: 2rem;
  padding-left: 2rem;
}
[selector="loop-inputs"] .row.justify-content-md-center > .col-md-auto [title="Add Item"]:hover{
  background-color: #000;
  color: #FFF;
  padding-right: 2rem;
  padding-left: 2rem;
}
[selector="loop-inputs"] .row.justify-content-md-center > .col-md-auto [title="Delete Item"]{
  padding-right: 2rem;
  padding-left: 2rem;
}
/* Loop */
[selector="loop"] {
  border: 1px solid #84171A;
}
[selector="loop"] .container-fluid {
  border-top: 1px solid #c5c5c542;
  padding-left: 1rem;
  padding-right: 1rem;
}
[selector="loop"] .container-fluid .row > div:last-child {
  border-right: 0px;
}
[selector="loop"] > div>div:nth-child(2n+1) {
  background-color: #ededed;
}
/* Hover Loop */
[selector="loop"] .container-fluid:hover{
  background-color: #F3F1EE;
  color: #84171A;
}
[selector="loop"] .row.justify-content-md-center > .col-md-auto [title="Add Item"]{
  background-color: #84171A;
  color: #FFF;
  padding-right: 2rem;
  padding-left: 2rem;
}
[selector="loop"] .row.justify-content-md-center > .col-md-auto [title="Add Item"]:hover{
  background-color: #000;
  color: #FFF;
  padding-right: 2rem;
  padding-left: 2rem;
}
[selector="loop"] .row.justify-content-md-center > .col-md-auto [title="Delete Item"]{
  padding-right: 2rem;
  padding-left: 2rem;
}
/* CheckBox */
[selector="checkbox"]>div>div>.form-check-input{
  width: 1.2em;
  height: 1.2em;
  accent-color: #84171A;
  margin-top: 0.2em;
}
[selector="checkbox"]>div>div>.form-check-label{
  margin-left: 0.25rem;
}
/* Radio */
[selector="radio"]>div>div>form>div>.form-check-input{
  accent-color: #84171A;
  width: 1.2em;
  height: 1.2em;
  margin-top: 0.2em;
}
[selector="radio"]>div>div>form>div>.form-check-label{
  margin-left: 0.25rem;
}
/* Buttons */
[selector="btn-w4"]>div>button{
  padding-left: 4em;
  padding-right: 4em;
}
[selector="errorLabel"] {
  color:red;
}
[selector='infoMessage'] {
  color: #86D2EA;
  background: #86d2ea1a;
  text-align: center;
  border: 1px solid #86D2EA;
  margin-top: 1rem;
}
[selector='header-loop'] {
  border-bottom: 2px solid var(--primary);
}
